<?php
namespace App\Services\Purchases; use App\Models\Purchases\PurchaseInvoice; use App\Models\User; use App\Services\AuditLogger; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class PurchaseInvoiceService {public function __construct(private readonly AuditLogger $audit){} /** @param array<string,mixed> $d */ public function create(User $u,array $d):PurchaseInvoice{return DB::transaction(function()use($u,$d){$lines=[];$subtotal=0;$cgst=0;$sgst=0;$igst=0;$cess=0;foreach($d['items']as $i){$q=(float)$i['quantity'];$rate=(float)$i['unit_price'];if($q<=0||$rate<0)throw ValidationException::withMessages(['items'=>'Quantity and rate must be valid.']);$taxable=round($q*$rate,2);$tax=round($taxable*((float)($i['tax_rate']??0))/100,2);$intra=($d['place_of_supply_state_code']??null)==($d['supplier_state_code']??null);$lCgst=$intra?$tax/2:0;$lSgst=$intra?$tax-$lCgst:0;$lIgst=$intra?0:$tax;$subtotal+=$taxable;$cgst+=$lCgst;$sgst+=$lSgst;$igst+=$lIgst;$lines[]=$i+['taxable_value'=>$taxable,'cgst_amount'=>$lCgst,'sgst_amount'=>$lSgst,'igst_amount'=>$lIgst,'cess_amount'=>0,'line_total'=>$taxable+$tax];}$total=round($subtotal+$cgst+$sgst+$igst+$cess,2);$fy=$d['financial_year']??now()->format('Y').'-'.now()->addYear()->format('y');$number='PINV-'.$fy.'-'.str_pad((string)(PurchaseInvoice::where('company_id',$u->company_id)->lockForUpdate()->count()+1),5,'0',STR_PAD_LEFT);$invoice=PurchaseInvoice::create(['company_id'=>$u->company_id,'branch_id'=>$u->branch_id,'warehouse_id'=>$d['warehouse_id']??null,'supplier_id'=>$d['supplier_id'],'purchase_order_id'=>$d['purchase_order_id']??null,'invoice_number'=>$number,'supplier_invoice_number'=>$d['supplier_invoice_number'],'supplier_invoice_date'=>$d['supplier_invoice_date'],'financial_year'=>$fy,'status'=>'draft','currency'=>$d['currency']??'INR','place_of_supply_state_code'=>$d['place_of_supply_state_code']??null,'reverse_charge'=>(bool)($d['reverse_charge']??false),'subtotal'=>$subtotal,'taxable_total'=>$subtotal,'input_cgst'=>$cgst,'input_sgst'=>$sgst,'input_igst'=>$igst,'input_cess'=>$cess,'grand_total'=>$total,'outstanding_total'=>$total,'due_date'=>$d['due_date']??null,'notes'=>$d['notes']??null,'created_by'=>$u->id]);foreach($lines as $l)$invoice->items()->create(['product_id'=>$l['product_id']??null,'name_snapshot'=>$l['name_snapshot']??'Purchase line','hsn_sac'=>$l['hsn_sac']??null,'quantity'=>$l['quantity'],'unit_price'=>$l['unit_price'],'taxable_value'=>$l['taxable_value'],'tax_rate'=>$l['tax_rate']??0,'cgst_amount'=>$l['cgst_amount'],'sgst_amount'=>$l['sgst_amount'],'igst_amount'=>$l['igst_amount'],'cess_amount'=>$l['cess_amount'],'line_total'=>$l['line_total']]);$this->audit->record('purchase.invoice.created',$invoice,'Purchase invoice created');return $invoice;});}}
